// Import necessary modules
const cron = require('node-cron');
const mongoose = require('mongoose');
const Task = require('./models/Task'); 
const NotificationLog = require('./models/NotificationLog');
const { sendTelegramNotification } = require('./services/telegramService');

/**
 * Scheduling Engine - Handles scheduling tasks and notifications.
 */
class SchedulingEngine {
  constructor() {
    this.initializeSchedules();
  }

  /**
   * Function to initialize all scheduled tasks.
   */
  initializeSchedules() {
    this.scheduleRecurringTasks();
  }

  /**
   * Schedule tasks based on their recurrence details using node-cron.
   */
  scheduleRecurringTasks() {
    Task.find({ status: 'active' }).then(tasks => {
      tasks.forEach(task => {
        const cronTime = this.constructCronTime(task.recurrence);
        cron.schedule(cronTime, () => {
          this.handleTaskExecution(task);
        });
      });
    }).catch(err => console.error('Error fetching tasks:', err));
  }

  /**
   * Construct cron time string from task's recurrence details.
   * @param {Object} recurrence - The recurrence object of the task.
   * @returns {string} Cron time format.
   */
  constructCronTime(recurrence) {
    if (recurrence.type === 'daily') {
      return `0 ${recurrence.time.split(':')[1]} ${recurrence.time.split(':')[0]} * * *`;
    } else if (recurrence.type === 'weekly') {
      const dayOfWeek = recurrence.daysOfWeek.join(',');
      return `0 ${recurrence.time.split(':')[1]} ${recurrence.time.split(':')[0]} * * ${dayOfWeek}`;
    }
    // Custom logic can be applied here.
    return '* * * * *'; // Default to every minute.
  }

  /**
   * Handle task execution and notifications
   * @param {Object} task - The task object to be executed.
   */
  handleTaskExecution(task) {
    const assigneeId = this.getCurrentAssignee(task);
    const message = `Task: ${task.title} is now assigned to ${assigneeId}`;

    // Send notification
    sendTelegramNotification(assigneeId, message)
      .then(() => {
        this.logNotification(task.id, 'success');
      })
      .catch(err => {
        console.error('Error sending notification:', err);
        this.logNotification(task.id, 'failed', err.message);
      });
  }

  /**
   * Get the current assignee based on rotation logic.
   * @param {Object} task - The task object.
   * @returns {string} Assignee ID.
   */
  getCurrentAssignee(task) {
    // Rotation logic to get the right assignee
    let currentIndex = task.rotationIndex;
    let availableAssignee = task.assignees[currentIndex];

    while (task.unavailableMembers.includes(availableAssignee)) {
      currentIndex = (currentIndex + 1) % task.assignees.length;
      availableAssignee = task.assignees[currentIndex];
    }
    // Update rotation index for next time
    task.rotationIndex = currentIndex;
    task.save();
    return availableAssignee;
  }

  /**
   * Log the notification result into NotificationLog.
   * @param {string} taskId - The task ID.
   * @param {string} status - Status of the notification.
   * @param {string} [errorDetails] - Error details, if any.
   */
  logNotification(taskId, status, errorDetails) {
    const logEntry = new NotificationLog({
      taskId,
      sentAt: new Date(),
      status,
      errorDetails: errorDetails || '',
      retryCount: status === 'failed' ? 1 : 0
    });
    logEntry.save().catch(err => console.error('Error logging notification:', err));
  }
}

// Instantiate the SchedulingEngine
new SchedulingEngine();
